import { forwardRef, useId } from "react";
import { clsx } from "clsx";
import { useCheckboxGroupContext } from "../../CheckboxGroup";
import { Label, type LabelCustomProps } from "../../Label";
import { CheckboxItem } from "../../CheckboxItem";
import * as styles from "./_CheckboxCompact.css";

/**
 * Label configuration for the compact checkbox.
 * Omits required (not applicable to individual items) and asChild (controlled internally).
 * The variant defaults to "normal" in this component.
 */
export type CheckboxCompactLabel = Omit<
  LabelCustomProps,
  "required" | "asChild"
>;

export interface CheckboxCompactProps {
  /**
   * The value of the checkbox (required for CheckboxGroup)
   */
  value: string;

  /**
   * The visible label configuration.
   * The variant defaults to "normal" in this component.
   */
  label: CheckboxCompactLabel;

  /**
   * Whether this checkbox is disabled
   */
  disabled?: boolean;

  /**
   * Whether to hide the focus ring on the CheckboxItem (parent handles focus styling)
   */
  hideFocusRing?: boolean;

  /**
   * Optional class applied to the root element
   */
  className?: string;
}

/**
 * @internal
 * A compact checkbox variant used internally by CheckboxFieldset.
 * This component is styled as a row within a list, with hover/focus states
 * on the entire row and a bottom border as divider.
 */
export const _CheckboxCompact = forwardRef<
  HTMLInputElement,
  CheckboxCompactProps
>(
  (
    { value, label, disabled = false, hideFocusRing = false, className },
    ref
  ) => {
    const generatedId = useId();
    const checkboxId = `${generatedId}-checkbox`;
    const labelId = `${generatedId}-label`;

    // Get state from CheckboxGroup context to determine if this item is checked
    const groupState = useCheckboxGroupContext();
    const isSelected = groupState.isSelected(value);
    const isInvalid = groupState.isInvalid;
    // Combine item-level disabled with group-level disabled
    const isDisabled = disabled || groupState.isDisabled;

    return (
      <label
        className={clsx(styles.compactContainer, className)}
        data-checked={isSelected || undefined}
        data-disabled={isDisabled || undefined}
        data-invalid={isInvalid || undefined}
      >
        <CheckboxItem
          ref={ref}
          value={value}
          id={checkboxId}
          aria-labelledby={labelId}
          disabled={disabled}
          hideFocusRing={hideFocusRing}
        />
        <Label variant="normal" {...label} id={labelId} asChild>
          <span>{label.children}</span>
        </Label>
      </label>
    );
  }
);

_CheckboxCompact.displayName = "_CheckboxCompact";
